                check(cells.size() == 10,
                    label + " should expose all represented records");
                if (cells.size() == 10) {
                    check(cells[0].reference.row == 1 &&
                            cells[0].reference.column == 1 &&
                            cells[0].value.kind() == fastxlsx::CellValueKind::Blank,
                        label + " should keep A1 blank first");
                    check(cells[1].reference.row == 1 &&
                            cells[1].reference.column == 2 &&
                            cells[1].value.kind() == fastxlsx::CellValueKind::Blank,
                        label + " should keep B1 blank after A1");
                    check(cells[9].reference.row == 4 &&
                            cells[9].reference.column == 4 &&
                            cells[9].value.kind() == fastxlsx::CellValueKind::Text &&
                            cells[9].value.text_value() == "clear-cell-range-mb-release",
                        label + " should keep D4 recovery text last");
                }
                const std::vector<fastxlsx::WorksheetCellSnapshot> row_one =
                    handle.row_cells(1);
                check(row_one.size() == 3 &&
                        row_one[0].reference.row == 1 &&
                        row_one[0].reference.column == 1 &&
                        row_one[0].value.kind() == fastxlsx::CellValueKind::Blank &&
                        row_one[1].reference.row == 1 &&
                        row_one[1].reference.column == 2 &&
                        row_one[1].value.kind() == fastxlsx::CellValueKind::Blank &&
                        row_one[2].reference.row == 1 &&
                        row_one[2].reference.column == 3 &&
                        row_one[2].value.kind() == fastxlsx::CellValueKind::Text &&
                        row_one[2].value.text_value() == "clear-range-c1",
                    label + " should keep row-one blanks and C1 text");
                const std::vector<fastxlsx::WorksheetCellSnapshot> row_two =
                    handle.row_cells(2);
                check(row_two.size() == 3 &&
                        row_two[0].reference.row == 2 &&
                        row_two[0].reference.column == 1 &&
                        row_two[0].value.kind() == fastxlsx::CellValueKind::Blank &&
                        row_two[1].reference.row == 2 &&
                        row_two[1].reference.column == 2 &&
                        row_two[1].value.kind() == fastxlsx::CellValueKind::Blank &&
                        row_two[2].reference.row == 2 &&
                        row_two[2].reference.column == 3 &&
                        row_two[2].value.kind() == fastxlsx::CellValueKind::Text &&
                        row_two[2].value.text_value() == "clear-range-c2",
                    label + " should keep row-two blanks and C2 text");
                const std::vector<fastxlsx::WorksheetCellSnapshot> row_three =
                    handle.row_cells(3);
